"""Corners-last placement with iterative radius expansion for n=26 circles"""
import numpy as np

def construct_packing():
    """
    Corners-last radius expansion for hexagonal packing.
    Within each iteration, circles processed: interior → edge → corner.
    This gives priority to interior circles, allowing corners to
    expand into remaining space after interior/edge are sized.
    """
    best_sum, best_c, best_r = 0, None, None
    patterns = [[5,6,5,6,4], [4,5,4,5,4,4], [5,4,5,4,5,3], [6,5,6,5,4]]

    for pat in patterns:
        for s in np.linspace(0.08, 0.22, 200):
            h = s * np.sqrt(3) / 2
            y0 = (1 - (len(pat) - 1) * h) / 2
            c = []
            for ri, cnt in enumerate(pat):
                y = y0 + ri * h
                x0 = (1 - (cnt - 1) * s) / 2
                off = s / 2 if ri % 2 else 0
                c.extend([[x0 + ci * s + off, y] for ci in range(cnt)])
            c = np.array(c)
            n = len(c)

            # Classify by proximity to edges/corners
            types = np.empty(n, dtype='<U8')
            for i in range(n):
                x, y = c[i]
                if (x < 0.15 and y < 0.15) or (x > 0.85 and y < 0.15) or \
                   (x < 0.15 and y > 0.85) or (x > 0.85 and y > 0.85):
                    types[i] = 'corner'
                elif x < 0.12 or x > 0.88 or y < 0.12 or y > 0.88:
                    types[i] = 'edge'
                else:
                    types[i] = 'interior'

            r = np.array([min(x, y, 1-x, 1-y) for x, y in c])

            # Phase 1: Fix interior circles first
            for _ in range(50):
                for i in range(n):
                    if types[i] == 'interior':
                        max_r = min(c[i,0], c[i,1], 1-c[i,0], 1-c[i,1])
                        for j in range(n):
                            if i != j and types[j] == 'interior':
                                d = np.linalg.norm(c[i] - c[j])
                                max_r = min(max_r, max(0, d - r[j]))
                        r[i] = max_r

            # Phase 2: Fix edge circles (interior already fixed)
            for _ in range(50):
                for i in range(n):
                    if types[i] == 'edge':
                        max_r = min(c[i,0], c[i,1], 1-c[i,0], 1-c[i,1])
                        for j in range(n):
                            if i != j and types[j] in ['interior', 'edge']:
                                d = np.linalg.norm(c[i] - c[j])
                                max_r = min(max_r, max(0, d - r[j]))
                        r[i] = max_r

            # Phase 3: Corners expand into remaining space
            for i in range(n):
                if types[i] == 'corner':
                    max_r = min(c[i,0], c[i,1], 1-c[i,0], 1-c[i,1])
                    for j in range(n):
                        if i != j:
                            d = np.linalg.norm(c[i] - c[j])
                            max_r = min(max_r, max(0, d - r[j]))
                    r[i] = max_r

            total = np.sum(r)
            if total > best_sum:
                best_sum, best_c, best_r = total, c.copy(), r.copy()

    return best_c, best_r, best_sum
